import android.content.Context
import java.util.Properties

/**
 * Loads secrets from local.properties (never committed to VCS)
 * or from environment variables in CI/CD.
 *
 * Setup:
 * 1. Add to local.properties (already in .gitignore):
 *      FACEBOOK_APP_ID=your_actual_app_id
 *      FACEBOOK_APP_SECRET=your_actual_secret
 *      GOOGLE_CLIENT_ID=your_actual_client_id
 *      GOOGLE_CLIENT_SECRET=your_actual_secret
 *
 * 2. In build.gradle.kts, inject as BuildConfig fields:
 *      android {
 *          defaultConfig {
 *              val props = Properties().apply {
 *                  rootProject.file("local.properties").inputStream().use { load(it) }
 *              }
 *              buildConfigField("String", "FACEBOOK_APP_ID", "\"${props["FACEBOOK_APP_ID"]}\"")
 *              buildConfigField("String", "GOOGLE_CLIENT_ID", "\"${props["GOOGLE_CLIENT_ID"]}\"")
 *              resValue("string", "facebook_app_id", "${props["FACEBOOK_APP_ID"]}")
 *          }
 *      }
 *
 * NOTE: Client secrets should NEVER be in the Android app.
 * Token exchange using secrets must happen on your backend server.
 */
object SecureConfig {
    // These come from BuildConfig which is populated from local.properties
    // local.properties is in .gitignore by default
    val facebookAppId: String
        get() = BuildConfig.FACEBOOK_APP_ID

    val googleClientId: String
        get() = BuildConfig.GOOGLE_CLIENT_ID

    // SECRETS MUST STAY ON YOUR BACKEND SERVER - NEVER IN THE APP
    // The OAuth token exchange flow should be:
    // 1. App gets authorization code from Facebook/Google
    // 2. App sends auth code to YOUR backend server
    // 3. Backend server (which has the secrets) exchanges code for tokens
    // 4. Backend server returns session token to app
}

