sealed class SocialLoginResult {
    data class Success(
        val provider: SocialProvider,
        val authorizationCode: String,
        val userId: String?,
        val email: String?,
        val displayName: String?
    ) : SocialLoginResult()

    data class Error(
        val provider: SocialProvider,
        val message: String,
        val exception: Throwable? = null
    ) : SocialLoginResult()

    data object Cancelled : SocialLoginResult()
}

enum class SocialProvider {
    FACEBOOK,
    GOOGLE
}

