import android.content.Context
import android.content.Intent
import androidx.activity.ComponentActivity
import androidx.activity.result.ActivityResultLauncher
import androidx.activity.result.contract.ActivityResultContracts
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInAccount
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions
import com.google.android.gms.common.api.ApiException
import com.google.android.gms.tasks.Task

class GoogleLoginHandler(
    private val activity: ComponentActivity,
    private val onResult: (SocialLoginResult) -> Unit
) {
    private val googleSignInClient: GoogleSignInClient
    private val signInLauncher: ActivityResultLauncher<Intent>

    init {
        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestIdToken(SecureConfig.googleClientId)
            .requestServerAuthCode(SecureConfig.googleClientId)
            .requestEmail()
            .requestProfile()
            .build()

        googleSignInClient = GoogleSignIn.getClient(activity, gso)

        signInLauncher = activity.registerForActivityResult(
            ActivityResultContracts.StartActivityForResult()
        ) { result ->
            val task = GoogleSignIn.getSignedInAccountFromIntent(result.data)
            handleSignInResult(task)
        }
    }

    fun login() {
        val signInIntent = googleSignInClient.signInIntent
        signInLauncher.launch(signInIntent)
    }

    private fun handleSignInResult(completedTask: Task<GoogleSignInAccount>) {
        try {
            val account = completedTask.getResult(ApiException::class.java)
            // Send the serverAuthCode to your BACKEND SERVER
            // The backend uses the client secret to exchange it for tokens
            onResult(
                SocialLoginResult.Success(
                    provider = SocialProvider.GOOGLE,
                    authorizationCode = account.serverAuthCode ?: account.idToken ?: "",
                    userId = account.id,
                    email = account.email,
                    displayName = account.displayName
                )
            )
        } catch (e: ApiException) {
            if (e.statusCode == 12501) {
                onResult(SocialLoginResult.Cancelled)
            } else {
                onResult(
                    SocialLoginResult.Error(
                        provider = SocialProvider.GOOGLE,
                        message = "Google sign-in failed (status: ${e.statusCode})",
                        exception = e
                    )
                )
            }
        }
    }

    fun logout() {
        googleSignInClient.signOut()
    }

    fun revokeAccess() {
        googleSignInClient.revokeAccess()
    }
}

